%[text] # 해리포터: 살아남은 아이의 흉터
%[text] 
%[text] ### 해리포터의 가장 상징적인 이미지는 동그란 안경과 번개 모양의 흉터일 것입니다.
%[text] ### 1. 번개 모양 흉터의 좌표 x값과 y값은 다음과 같을 때, 번개 모양 흉터를 점을 이어 그리고 3차 다항식을 구해주세요.
%[text] ### x = \[-3.0 -2.0 -1.3 -0.4\]   y = \[2.8  1.2  1.7  0.0 \]
%[text] 
%[text] ### 2. 번개 모양 흉터 좌표에 1~3차 다항식을  plot으로 그려주세요.
clear; clf; %[output:04e59cc4]
x = [-3.0 -2.0 -1.3 -0.4];
y = [ 2.8  1.2  1.7  0.0];
plot(x, y) %[output:04e59cc4]
polyfit(x, y, 3);

for k = 1:3
    p = polyfit(x,y,k);
    gx = linspace(-3, -0.5, 100);
    gy = polyval(p, gx);
    
    plot(gx, gy); %[output:635fdabd]
    hold on;
end
legend show; %[output:635fdabd]
xlabel('x'); %[output:635fdabd]
ylabel('y'); %[output:635fdabd]
title('Harry Potter: The Boy Who Lived'); %[output:635fdabd]
%[text] 
